 1→import { createAssembly } from './assemblyModels';
 2→import { createSketchObject } from './objectModels';
 3→import { getTemplate } from './templates/templateRegistry';
 4→import { materializePartDefinition } from './templates/templateHelpers';
 5→
 6→function applyOrigin(position = {}, origin = {}) {
 7→  return {
 8→    x: (Number(position.x) || 0) + (Number(origin.x) || 0),
 9→    y: (Number(position.y) || 0) + (Number(origin.y) || 0),
10→    z: (Number(position.z) || 0) + (Number(origin.z) || 0),
11→  };
12→}
